const Blog = () => {
  const { allMarkdownRemark } = useStaticQuery(graphql`
    {
      allMarkdownRemark {
        edges {
          node {
            id
            frontmatter {
              title
              path
            }
          }
        }
      }
    }
  `)

  const { edges } = allMarkdownRemark

  const posts = edges.map(element => {
    const { node } = element
    const { frontmatter, id } = node

    return (
      <li key={id}>
        <Link to={frontmatter.path}>{frontmatter.title}</Link>
      </li>
    )
  })

  return (
    <Layout>
      <SEO title="Blog" />
      <ul>{posts}</ul>
    </Layout>
  )
}

export default Blog
